mapper.select:
SELECT t1.id as id, t1.currency as currency, t1.invite_code as inviteCode, t1.register_time as registerTime, t1.user_id as userId, t1.user_account as userAccount, t1.target_account as targetAccount, t1.target_user_id as targetUserId, t1.creator as creator, t1.created_time as createdTime, t1.updater as updater, t1.updated_time as updatedTime, t2.first_deposit_time as firstDepositTime FROM `site_user_invite_record` t1, user_info t2 where t1.target_user_id = t2.user_id and t2.site_code = #{vo.siteCode}
AND t1.register_time >= #{vo.startTime}
AND t1.register_time <= #{vo.endTime}
AND t1.user_account = #{vo.userAccount}
AND t1.target_account = #{vo.targetAccount}
AND t1.invite_code = #{vo.inviteCode}
order by t2.first_deposit_time desc

SELECT t1.id as id, t1.currency as currency, t1.invite_code as inviteCode, t1.register_time as registerTime, t1.user_id as userId, t1.user_account as userAccount, t1.target_account as targetAccount, t1.target_user_id as targetUserId, t1.creator as creator, t1.created_time as createdTime, t1.updater as updater, t1.updated_time as updatedTime, t2.first_deposit_time as firstDepositTime, t2.first_deposit_amount as firstDepositAmount FROM `site_user_invite_record` t1, user_info t2 where t1.target_user_id = t2.user_id and t2.first_deposit_time is not null and t2.first_deposit_amount > 0 and t2.site_code = #{vo.siteCode}
AND t2.register_time >= #{vo.startTime}
AND t2.register_time <= #{vo.endTime}
AND t1.user_id = #{vo.userId}
AND t1.user_account = #{vo.userAccount}
AND t2.first_deposit_time >= #{vo.startTime}
AND t2.first_deposit_time <= #{vo.endTime}
